commit 83c8ca9df867426f9a8d37ede555b0ab936e6173
Author: Andy Kipp <123@321.123>
Date:   Fri Apr 17 01:14:39 2026 +0600

    docs
---
 docs/_templates/page.html | 46 ++++++++++++++++++++++++++++++++++++++++++++++
 1 file changed, 46 insertions(+)

diff --git a/docs/_templates/page.html b/docs/_templates/page.html
new file mode 100644
index 00000000..bbe490f0
--- /dev/null
+++ b/docs/_templates/page.html
@@ -0,0 +1,46 @@
+{#-
+    Injects per-page JSON-LD (TechArticle + BreadcrumbList) into the <head>
+    of every doc page rendered by Furo. The landing page at `/` uses a
+    separate standalone template (``_templates/index.html`` via
+    ``html_additional_pages``) and is unaffected.
+
+    `pageurl` is populated by Sphinx only when `html_baseurl` is set in
+    conf.py — the ``{% if pageurl %}`` guard keeps dev builds without a
+    base URL safe. IDs ``#website``/``#software``/``#org`` reference the
+    graph nodes defined in the landing-page JSON-LD, linking this page
+    into the same semantic graph.
+-#}
+{% extends "!page.html" %}
+{% block extrahead %}
+  {{ super() }}
+  {%- if pageurl %}
+  <script type="application/ld+json">{
+    "@context": "https://schema.org",
+    "@graph": [
+      {
+        "@type": "TechArticle",
+        "@id": {{ (pageurl ~ "#techarticle") | tojson }},
+        "headline": {{ title | striptags | tojson }},
+        "url": {{ pageurl | tojson }},
+        "isPartOf": {"@id": "https://xon.sh/#website"},
+        "about": {"@id": "https://xon.sh/#software"},
+        "inLanguage": "en",
+        "author": {"@id": "https://xon.sh/#org"},
+        "publisher": {"@id": "https://xon.sh/#org"}
+      },
+      {
+        "@type": "BreadcrumbList",
+        "itemListElement": [
+          {"@type": "ListItem", "position": 1, "name": "Home", "item": "https://xon.sh/"}
+          {%- if pagename != master_doc -%}
+          ,{"@type": "ListItem", "position": 2, "name": "Contents", "item": "https://xon.sh/contents.html"}
+          ,{"@type": "ListItem", "position": 3, "name": {{ title | striptags | tojson }}, "item": {{ pageurl | tojson }}}
+          {%- else -%}
+          ,{"@type": "ListItem", "position": 2, "name": {{ title | striptags | tojson }}, "item": {{ pageurl | tojson }}}
+          {%- endif %}
+        ]
+      }
+    ]
+  }</script>
+  {%- endif %}
+{% endblock %}

